using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<pair<string, string>> validCoupons;

    // Define the order of business lines
    vector<string> businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    // Check each coupon
    for (size_t i = 0; i < code.size(); ++i) {
        // Check if code is valid
        bool isValidCode = !code[i].empty() && code[i].find_first_not_of("0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ_") == string::npos;
        // Check if business line is valid
        bool isValidBusiness = find(businessOrder.begin(), businessOrder.end()) != find(businessOrder.begin(), businessOrder.end(), businessLine[i]);
        // Check if active
        bool isActive = isActive[i];

        if (isValidCode && isValidBusiness && isActive) {
            validCoupons.push_back({code[i], businessLine[i]});
        }
    }

    // Sort by business line order and then by code lexicographically
    sort(validCoupons.begin(), validCoupons.end(), [](const pair<string, string>& a, const pair<string, string>& b) {
        // Compare business lines based on the defined order
        int orderA = find(businessOrder.begin(), businessOrder.end(), a.second) - businessOrder.begin();
        int orderB = find(businessOrder.begin(), businessOrder.end(), b.second) - businessOrder.begin();
        if (orderA != orderB) return orderA < orderB;
        // If business lines are the same, compare codes lexicographically
        return a.first < b.first;
    });

    // Extract the codes in the sorted order
    vector<string> result;
    for (const auto& coupon : validCoupons) {
        result.push_back(coupon.first);
    }

    return result;
}

