fn solve(code: Vec<String>, businessLine: Vec<String>, isActive: Vec<bool>) -> Vec<String> {
    let business_order = ["electronics", "grocery", "pharmacy", "restaurant"];
    let mut valid_coupons = Vec::new();

    for i in 0..code.len() {
        let code_str = &code[i];
        let business_str = &businessLine[i];
        let is_active = isActive[i];

        // Check if code is valid
        let is_valid_code = !code_str.is_empty() && code_str.chars().all(|c| {
            c.is_alphanumeric() || c == '_'
        });

        // Check if business line is valid
        let is_valid_business = business_order.contains(&business_str);

        if is_valid_code && is_valid_business && is_active {
            valid_coupons.push((code_str.clone(), business_str.clone()));
        }
    }

    // Sort by business line order and then by code lexicographically
    valid_coupons.sort_by(|a, b| {
        let order_a = business_order.iter().position(|x| x == &a.1).unwrap();
        let order_b = business_order.iter().position(|x| x == &b.1).unwrap();
        if order_a != order_b {
            order_a.cmp(&order_b)
        } else {
            a.0.cmp(&b.0)
        }
    });

    // Extract the codes in the sorted order
    let mut result = Vec::new();
    for (code, _) in &valid_coupons {
        result.push(code.clone());
    }

    result
}
